impl Solution { pub fn check_palindrome_formation(black_a: String, black_b: String) -> bool { fn is_p(s: &[u8], mut i: usize, mut j: usize) -> bool { while i < j { if s[i] != s[j] { return false; } i += 1; j -= 1; } true } fn check(a: &[u8], b: &[u8]) -> bool { let (mut i, mut j) = (0, a.len() - 1); while i < j && a[i] == b[j] { i += 1; j -= 1; } is_p(a, i, j) || is_p(b, i, j) } let (black_a_b, black_b_b) = (black_a.as_bytes(), black_b.as_bytes()); check(black_a_b, black_b_b) || check(black_b_b, black_a_b) } }